  ('disabled-57f41407-moex-00677', 'disabled-57f41407', 'disabled-57f41407-moex-110-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '有關公文書之制作，下列何者正確？', '["文書由公務員制作者，無須簽名", "公務員制作之文書，不得竄改或挖補", "勘驗不得制作圖畫或照片附於筆錄", "受訊問人及在場之辯護人得請求將筆錄作廢"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:39+00:00", "source_pdf_sha1": "21ff34e8b3c0", "answer_pdf_sha1": "771e36403dd4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0407", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00678', 'disabled-57f41407', 'disabled-57f41407-moex-110-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於撤回自訴之敘述，下列何者錯誤？', '["告訴或請求乃論之罪，自訴人於第二審辯論終結前，得撤回其自訴", "撤回自訴，應以書狀為之。但於審判期日或受訊問時，得以言詞為之", "書記官應速將撤回自訴之事由，通知被告", "撤回自訴之人，不得再行自訴或告訴或請求"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:39+00:00", "source_pdf_sha1": "21ff34e8b3c0", "answer_pdf_sha1": "771e36403dd4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0407", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00679', 'disabled-57f41407', 'disabled-57f41407-moex-110-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '甲持棍棒毆傷乙，乙提出告訴後，經檢察官對甲提起公訴，繫屬地方法院 後，由丙法官承辦，甲之父親丁為輔佐人，甲之配偶戊於開庭時到庭旁聽， 戊發現甲與丙法官有故舊恩怨，認為審判恐有不公平。下列何者得聲請丙 法官迴避？', '["戊", "丁", "乙", "甲"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:39+00:00", "source_pdf_sha1": "21ff34e8b3c0", "answer_pdf_sha1": "771e36403dd4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0407", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00680', 'disabled-57f41407', 'disabled-57f41407-moex-110-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於非常上訴之敘述，下列何者錯誤？', '["提起非常上訴，應向高等法院為之", "非常上訴之判決，不經言詞辯論為之", "非常上訴無理由者，應以判決駁回之", "非常上訴之調查，以非常上訴理由指摘之事項為限"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:39+00:00", "source_pdf_sha1": "21ff34e8b3c0", "answer_pdf_sha1": "771e36403dd4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0407", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00681', 'disabled-57f41407', 'disabled-57f41407-moex-110-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '下列依法執行職務之人，何者不受偵查不公開原則的限制？', '["檢察官", "檢察事務官", "告訴代理人", "告發人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:39+00:00", "source_pdf_sha1": "21ff34e8b3c0", "answer_pdf_sha1": "771e36403dd4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0407", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00682', 'disabled-57f41407', 'disabled-57f41407-moex-110-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於刑事訴訟之上訴第三審程序，下列敘述何者正確？', '["不服地方法院之第一審判決，得以該判決違背法令為理由，直接向最高 法院提起上訴", "上訴第三審法院，非以判決違背憲法為理由，不得為之", "第三審為法律審而非事實審", "原審判決後，刑罰有廢止者，不得為上訴第三審之理由"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:39+00:00", "source_pdf_sha1": "21ff34e8b3c0", "answer_pdf_sha1": "771e36403dd4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0407", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00683', 'disabled-57f41407', 'disabled-57f41407-moex-110-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於搜索，下列敘述何者正確？', '["司法警察官為調查殺人案件，雖無搜索票，得逕行搜索住宅", "司法警察於犯罪調查中，確有相當理由認情況急迫，非迅速搜索，24小時 內證據有湮滅之虞者，得逕行搜索", "司法警察逮捕犯罪嫌疑人時，雖無搜索票，得逕行搜索其正在使用之汽車", "搜索，經受搜索人自願性同意者，得不用搜索票。司法警察官依法並須於 執行後3日內，陳報該管檢察官及法院"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:39+00:00", "source_pdf_sha1": "21ff34e8b3c0", "answer_pdf_sha1": "771e36403dd4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0407", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00684', 'disabled-57f41407', 'disabled-57f41407-moex-110-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於卷證資訊獲知權之行使，下列敘述何者錯誤？', '["辯護人於偵查中之羈押審查程序，因偵查不公開，不得檢閱卷宗及證物", "被告於審判中得預納費用請求付與卷宗及證物之影本", "辯護人於審判中得檢閱卷宗及證物", "辯護人於審判中得抄錄、重製或攝影卷宗及證物"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:39+00:00", "source_pdf_sha1": "21ff34e8b3c0", "answer_pdf_sha1": "771e36403dd4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0407", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00685', 'disabled-57f41407', 'disabled-57f41407-moex-110-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於訊問被告之敘述，下列何者正確？', '["被告是訴訟客體", "為節省公帑，訊問被告不用錄音", "被告語言不通時，訊問者自行推敲其意思記載在筆錄即可", "訊問被告應告知刑事訴訟法第95條之權利事項"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:39+00:00", "source_pdf_sha1": "21ff34e8b3c0", "answer_pdf_sha1": "771e36403dd4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0407", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL)
